content:
n(&serde_json::json!({}))
            .send()
        {
            Ok(resp) if resp.status().is_success() => return,
            _ => continue,
        }
    }
    // All retries exhausted — session data is safe in .jsonl.gz, adapter picks it up later
}
fn compute_duration_ms(path: &std::path::Path) -> u64 {
    let file = match fs::File::open(path) {
        Ok(f) => f,
        Err(_) => return 0,
    };
    let reader = BufReader::new(file);
    if let Some(Ok(first_line)) = reader.lines().next()
        && let Ok(obj) = serde_json::from_str::<serde_json::Value>(&first_line)
        && let Some(ts_str) = obj.get("timestamp").and_then(|t| t.as_str())
        && let Some(start_secs) = parse_iso_epoch_secs(ts_str)
    {
        let now_secs = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap_or_default()
            .as_secs();
        return now_secs.saturating_sub(start_secs) * 1000;
    }
    0
}
